    // \u521b\u5efa\u65e5\u671f\r\n        private List<string> transactions; // \u4ea4\u6613\u8bb0\u5f55\r\n\r\n        // ========== \u6784\u9020\u65b9\u6cd5 ==========\r\n        public BankAccount(string accountNumber, string holderName)\r\n        {\r\n            this.accountNumber = accountNumber;\r\n            this.holderName = holderName;\r\n            this.balance = 0;\r\n            this.createDate = DateTime.Now;\r\n            this.transactions = new List<string>();\r\n            \r\n            // \u8bb0\u5f55\u5f00\u6237\u4ea4\u6613\r\n            RecordTransaction($"\u5f00\u6237\uff0c\u521d\u59cb\u4f59\u989d: \xa50.00");\r\n        }\r\n\r\n        // ========== \u65b9\u6cd5 ==========\r\n        \r\n        // \u5b58\u6b3e\r\n        public void Deposit(decimal amount)\r\n        {\r\n            if (amount <= 0)\r\n            {\r\n                Console.WriteLine("\u5b58\u6b3e\u91d1\u989d\u5fc5\u987b\u5927\u4e8e0\uff01");\r\n                return;\r\n            }\r\n            \r\n            balance += amount;\r\n            RecordTransaction($"\u5b58\u6b3e: +\xa5{amount:F2}\uff0c\u4f59\u989d: \xa5{balance:F2}");\r\n            Console.WriteLine($"\u5b58\u6b3e\u6210\u529f\uff01\u5b58\u5165 \xa5{amount:F2}");\r\n        }\r\n\r\n        // \u53d6\u6b3e\r\n        public bool Withdraw(decimal amount)\r\n        {\r\n            if (amount <= 0)\r\n            {\r\n                Console.WriteLine("\u53d6\u6b3e\u91d1\u989d\u5fc5\u987b\u5927\u4e8e0\uff01");\r\n                return false;\r\n            }\r\n            \r\n            if (amount > balance)\r\n            {\r\n                Console.WriteLine($"\u4f59\u989d\u4e0d\u8db3\uff01\u5f53\u524d\u4f59\u989d: \xa5{balance:F2}\uff0c\u9700\u8981: \xa5{amount:F2}");\r\n                return false;\r\n            }\r\n            \r\n            balance -= amount;\r\n            RecordTransaction($"\u53d6\u6b3e: -\xa5{amount:F2}\uff0c\u4f59\u989d: \xa5{balance:F2}");\r\n            Console.WriteLine($"\u53d6\u6b3e\u6210\u529f\uff01\u53d6\u51fa \xa5{amount:F2}");\r\n            return true;\r\n        }\r\n\r\n        // \u67e5\u8be2\u4f59\u989d\r\n        public decimal GetBalance()\r\n        {\r\n            return balance;\r\n        }\r\n\r\n        // \u6253\u5370\u8d26\u6237\u4fe1\u606f\r\n        public void PrintInfo()\r\n        {\r\n            Console.WriteLine("\\n========== \u8d26\u6237\u4fe1\u606f ==========");\r\n            Console.WriteLine($"\u8d26\u6237\u53f7: {accountNumber}");\r\n            Console.WriteLine($"\u6301\u6709\u4eba: {holderName}");\r\n            Console.WriteLine($"\u5f53\u524d\u4f59\u989d: \xa5{balance:F2}");\r\n            Console.WriteLine($"\u5f00\u6237\u65e5\u671f: {createDate:yyyy-MM-dd HH:mm}");\r\n            Console.WriteLine("==============================\\n");\r\n        }\r\n\r\n        // \u6253\u5370\u4ea4\u6613\u8bb0\u5f55\r\n        public void PrintTransactions()\r\n        {\r\n            Console.WriteLine("\\n========== \u4ea4\u6613\u8bb0\u5f55 ==========");\r\n            if (transactions.Count == 0)\r\n            {\r\n                Console.WriteLine("\u6682\u65e0\u4ea4\u6613\u8bb0\u5f55");\r\n            }\r\n            else\r\n            {\r\n                foreach (var transaction in transactions)\r\n                {\r\n                    Console.WriteLine(transaction);\r\n                }\r\n            }\r\n            Console.WriteLine("==============================\\n");\r\n        }\r\n\r\n        // \u8ba1\u7b97\u5229\u606f\uff08\u5e74\u5229\u73873%\uff0c\u8ba1\u7b97\u672c\u6708\u5229\u606f\uff09\r\n        public void CalculateInterest()\r\n        {\r\n            decimal monthlyRate = 0.03m / 12; // \u6708\u5229\u7387\r\n            decimal interest = balance * monthlyRate;\r\n            balance += interest;\r\n            RecordTransaction($"\u5229\u606f\u7ed3\u7b97: +\xa5{interest:F2}\uff0c\u4f59\u989d: \xa5{balance:F2}");\r\n            Console.WriteLine($"\u5229\u606f\u5df2\u7ed3\u7b97\uff01\u83b7\u5f97\u5229\u606f: \xa5{interest:F2}");\r\n        }\r\n\r\n        // \u79c1\u6709\u65b9\u6cd5\uff1a\u8bb0\u5f55\u4ea4\u6613\r\n        private void RecordTransaction(string description)\r\n        {\r\n            string record = $"[{DateTime.Now:yyyy-MM-dd HH:mm:ss}] {description}";\r\n            transactions.Add(record);\r\n        }\r\n    }\r\n\r\n    // \u7a0b\u5e8f\u5165\u53e3\r\n    class Program\r\n    {\r\n        static void Main(string[] args)\r\n        {\r\n            Console.WriteLine("=== \u6b22\u8fce\u4f7f\u7528\u7b80\u6613\u94f6\u884c\u8d26\u6237\u7cfb\u7edf ===\\n");\r\n            \r\n            // \u521b\u5efa\u8d26\u6237\r\n            Console.Write("\u8bf7\u8f93\u5165\u8d26\u6237\u53f7: ");\r\n            string accNum = Console.ReadLine();\r\n            Console.Write("\u8bf7\u8f93\u5165\u6301\u6709\u4eba\u59d3\u540d: ");\r\n            string name = Console.ReadLine();\r\n            \r\n            BankAccount myAccount = new BankAccount(accNum, name);\r\n            Console.WriteLine("\\n\u8d26\u6237\u521b\u5efa\u6210\u529f\uff01\\n");\r\n\r\n            // \u4e3b\u83dc\u5355\u5faa\u73af\r\n            bool running = true;\r\n            while (running)\r\n            {\r\n                Console.WriteLine("\u8bf7\u9009\u62e9\u64cd\u4f5c\uff1a");\r\n                Console.WriteLine("1. \u5b58\u6b3e");\r\n                Console.WriteLine("2. \u53d6\u6b3e");\r\n                Console.WriteLine("3. \u67e5\u8be2\u4f59\u989d");\r\n                Console.WriteLine("4. \u67e5\u770b\u8d26\u6237\u4fe1\u606f");\r\n                Console.WriteLine("5. \u67e5\u770b\u4ea4\u6613\u8bb0\u5f55");\r\n                Console.WriteLine("6. \u7ed3\u7b97\u5229\u606f");\r\n                Console.WriteLine("0. \u9000\u51fa");\r\n                Console.Write("\\n> ");\r\n                \r\n                string choice = Console.ReadLine();\r\n                Console.WriteLine();\r\n\r\n                switch (choice)\r\n                {\r\n                    case "1":\r\n                        Console.Write("\u8bf7\u8f93\u5165\u5b58\u6b3e\u91d1\u989d: ");\r\n                        if (decimal.TryParse(Console.ReadLine(), out decimal depositAmount))\r\n                        {\r\n                            myAccount.Deposit(depositAmount);\r\n                        }\r\n                        else\r\n                        {\r\n                            Console.WriteLine("\u8f93\u5165\u65e0\u6548\uff01");\r\n                        }\r\n                        break;\r\n\r\n                    case "2":\r\n                        Console.Write("\u8bf7\u8f93\u5165\u53d6\u6b3e\u91d1\u989d: ");\r\n                        if (decimal.TryParse(Console.ReadLine(), out decimal withdrawAmount))\r\n                        {\r\n                            myAccount.Withdraw(withdrawAmount);\r\n                        }\r\n                        else\r\n                        {\r\n                            Console.WriteLine("\u8f93\u5165\u65e0\u6548\uff01");\r\n                        }\r\n                        break;\r\n\r\n                    case "3":\r\n                        Console.WriteLine($"\u5f53\u524d\u4f59\u989d: \xa5{myAccount.GetBalance():F2}\\n");\r\n                        break;\r\n\r\n                    case "4":\r\n                        myAccount.PrintInfo();\r\n                        break;\r\n\r\n                    case "5":\r\n                        myAccount.PrintTransactions();\r\n                        break;\r\n\r\n                    case "6":\r\n                        myAccount.CalculateInterest();\r\n                        break;\r\n\r\n                    case "0":\r\n                        running = false;\r\n                        Console.WriteLine("\u611f\u8c22\u4f7f\u7528\uff0c\u518d\u89c1\uff01");\r\n                        break;\r\n\r\n                    default:\r\n                        Console.WriteLine("\u65e0\u6548\u9009\u9879\uff0c\u8bf7\u91cd\u65b0\u9009\u62e9\u3002\\n");\r\n                        break;\r\n                }\r\n                \r\n                if (running)\r\n                {\r\n                    Console.WriteLine("\u6309\u4efb\u610f\u952e\u7ee7\u7eed...");\r\n                    Console.ReadKey();\r\n                    Console.Clear();\r\n                }\r\n            }\r\n        }\r\n    }\r\n}\n'})})}function d(n={}){const{wrapper:r}={...(0,i.R)(),...n.components};return r?(0,o.jsx)(r,{...n,children:(0,o.jsx)(u,{...n})}):u(n)}},28453(n,r,e){e.d(r,{R:()=>a,x:()=>s});var t=e(96540);const o={},i=t.createContext(o);function a(n){const r=t.useContext(i);return t.useMemo(function(){return"function"==typeof n?n(r):{...r,...n}},[r,n])}function s(n){let r;return r=n.disableParentContext?"function"==typeof n.components?n.components(o):n.components||o:a(n.components),t.createElement(i.Provider,{value:r},n.children)}}}]);